  ('pukao-0a2fc18c-moex-00216', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '下列何種情況發生時，會使得勞動需求曲線向右移動？', '["基本工資調低", "基本工資調高", "勞工的邊際生產力提升", "勞工的邊際生產力下降"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00217', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '下列何者不是造成市場失靈的原因？', '["外部性", "競爭者的加入", "公共財", "市場的獨占力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00218', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '下列那一類的財貨或服務，具有「非敵對性」的特性？', '["收聽廣播", "使用共享腳踏車，例如UBike", "餐飲外帶服務", "餐飲內用服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00219', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '當政府對具有外部性的財貨進行補貼時，其單位補貼金額應該等於：', '["邊際外部利益", "邊際願付價格", "邊際效用", "邊際成本"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00220', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '若1990年與2020年的消費者物價指數（CPI）分別是66與102（2016年為基期），阿美在1990年買一個 肉粽需40元，在2020年買了一個肉粽需60元，下列敘述何者正確？（四捨五入，取至小數點以下兩位）', '["1990年的肉粽，在2016年需花新臺幣58.82元", "2020年的肉粽，在2016年需花新臺幣60.61元", "1990年的肉粽，在2020年需花新臺幣61.82元", "與2020年相比，1990年買一個肉粽相對便宜"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL),
  ('pukao-0a2fc18c-moex-00221', 'pukao-0a2fc18c', 'pukao-0a2fc18c-moex-111-6948958a', 'sub-pukao-0a2fc18c-02', NULL, 'single_choice', '有關失業的成本（costsoftheunemployment），下列敘述何者錯誤？', '["失業的成本包括產出下滑等經濟成本（economiccosts）、失業者抑鬱和自尊受損等心理成本（psychological costs），和自殺與犯罪率增加等社會成本（socialcosts）", "失業的經濟成本（economiccosts）完全是由失業者自己承擔，因為失業者失去了工作收入；而經濟社會 並沒有承擔任何的經濟成本，社會承擔的是自殺與犯罪率增加等的社會成本", "失業救濟金（unemploymentbenefits）可以部分降低失業者的經濟壓力、心理及社會成本（psychological andsocialcosts），但卻可能拖長了失業期間", "失業期間越長，人們面臨的經濟與心理成本就越高，解決失業的代價就越高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:11+00:00", "source_pdf_sha1": "3d16c42cf235", "answer_pdf_sha1": "a2c37693d48b", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "420", "s": "0909", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "經建行政"}'::jsonb, NULL)
